<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Kanban Board</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      margin: 0;
      padding: 20px;
      background-color: #f5f5f5;
    }
    .board {
      display: flex;
      gap: 16px;
      max-width: 1200px;
      margin: 0 auto;
    }
    .column {
      flex: 1;
      min-width: 300px;
      background-color: #fff;
      border-radius: 8px;
      box-shadow: 0 2px 6px rgba(0,0,0,0.1);
      overflow: hidden;
    }
    .column-header {
      padding: 12px 16px;
      font-weight: bold;
      color: #333;
      border-bottom: 1px solid #eee;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    .count {
      background-color: #e0e0e0;
      padding: 2px 8px;
      border-radius: 12px;
      font-size: 14px;
    }
    .card-container {
      min-height: 60px;
      padding: 8px;
    }
    .card {
      background-color: #fff;
      border: 1px solid #ddd;
      border-radius: 6px;
      padding: 12px;
      margin-bottom: 8px;
      cursor: grab;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    .card:hover {
      box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    }
    .card-del {
      background: none;
      border: none;
      color: #ff5252;
      cursor: pointer;
      font-size: 18px;
      padding: 0 4px;
    }
    .card-del:hover {
      color: #d32f2f;
    }
    .new-card-row {
      margin-bottom: 16px;
      display: flex;
      gap: 8px;
    }
    #new-card {
      flex-grow: 1;
      padding: 8px 12px;
      border: 1px solid #ddd;
      border-radius: 4px;
      font-size: 16px;
    }
    #add-card {
      padding: 8px 16px;
      background-color: #4caf50;
      color: white;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      font-size: 16px;
    }
    #add-card:hover {
      background-color: #388e3c;
    }
  </style>
</head>
<body>
  <div class="board">
    <div id="col-todo" class="column" data-col="todo">
      <div class="column-header">
        To Do
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
    <div id="col-doing" class="column" data-col="doing">
      <div class="column-header">
        Doing
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
    <div id="col-done" class="column" data-col="done">
      <div class="column-header">
        Done
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </div>
  </div>
  <div class="new-card-row">
    <input type="text" id="new-card" placeholder="Enter a new card title..." />
    <button id="add-card">Add Card</button>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      const cols = {
        todo: { el: document.getElementById('col-todo'), container: document.querySelector('#col-todo .card-container') },
        doing: { el: document.getElementById('col-doing'), container: document.querySelector('#col-doing .card-container') },
        done: { el: document.getElementById('col-done'), container: document.querySelector('#col-done .card-container') }
      };
      const newCardInput = document.getElementById('new-card');
      const addCardBtn = document.getElementById('add-card');

      // Load state from localStorage
      let cards = JSON.parse(localStorage.getItem('kanbanCards')) || [];
      render();

      function render() {
        Object.values(cols).forEach(c => c.container.innerHTML = '');
        cards.forEach(card => {
          const cardEl = document.createElement('div');
          cardEl.className = 'card';
          cardEl.textContent = card.title;
          cardEl.draggable = true;
          cardEl.dataset.id = card.id;

          const delBtn = document.createElement('button');
          delBtn.className = 'card-del';
          delBtn.innerHTML = '&times;';
          delBtn.addEventListener('click', (e) => {
            e.stopPropagation();
            removeCard(card.id);
          });
          cardEl.appendChild(delBtn);

          cols[card.col].container.appendChild(cardEl);
        });

        updateCounts();

        // Setup drag events
        Object.values(cols).forEach(c => {
          c.container.addEventListener('dragover', (e) => {
            e.preventDefault();
          });
          c.container.addEventListener('drop', (e) => {
            e.preventDefault();
            const cardId = e.dataTransfer.getData('text/plain');
            moveCard(cardId, c.el.dataset.col);
          });
        });

        // Setup dragstart for cards
        document.querySelectorAll('.card').forEach(cardEl => {
          cardEl.addEventListener('dragstart', (e) => {
            e.dataTransfer.setData('text/plain', cardEl.dataset.id);
          });
        });
      }

      function updateCounts() {
        Object.entries(cols).forEach(([col, { el }]) => {
          const count = cards.filter(c => c.col === col).length;
          el.querySelector('.count').textContent = count;
        });
      }

      addCardBtn.addEventListener('click', () => {
        const title = newCardInput.value.trim();
        if (title) {
          addCard(title);
          newCardInput.value = '';
        }
      });

      function addCard(title, col = 'todo') {
        const id = Date.now().toString(36) + Math.random().toString(36).substr(2);
        cards.push({ id, title, col });
        save();
        render();
      }

      function moveCard(id, newCol) {
        const cardIndex = cards.findIndex(c => c.id === id);
        if (cardIndex !== -1) {
          cards[cardIndex].col = newCol;
          save();
          render();
        }
      }

      function removeCard(id) {
        cards = cards.filter(c => c.id !== id);
        save();
        render();
      }

      function save() {
        localStorage.setItem('kanbanCards', JSON.stringify(cards));
      }
    });
  </script>
</body>
</html>
